class FenwickTree2D:
    def __init__(self, matrix):
        if not matrix or not matrix[0]:
            self.rows = 0
            self.cols = 0
            self.tree = []
            self.original_matrix_values = []
            return

        self.rows = len(matrix)
        self.cols = len(matrix[0])
        self.tree = [[0] * (self.cols + 1) for _ in range(self.rows + 1)]
        self.original_matrix_values = [[0] * self.cols for _ in range(self.rows)]

        for r in range(self.rows):
            for c in range(self.cols):
                self._update_tree_internal(r + 1, c + 1, matrix[r][c])
                self.original_matrix_values[r][c] = matrix[r][c]

    def _update_tree_internal(self, r_idx, c_idx, val):
        # r_idx, c_idx are 1-based indices for the tree
        while r_idx <= self.rows:
            current_c_idx = c_idx
            while current_c_idx <= self.cols:
                self.tree[r_idx][current_c_idx] += val
                current_c_idx += current_c_idx & (-current_c_idx)
            r_idx += r_idx & (-r_idx)

    def update(self, row, col, val):
        # row, col are 0-based indices for the matrix
        if not (0 <= row < self.rows and 0 <= col < self.cols):
            return

        diff = val - self.original_matrix_values[row][col]
        self.original_matrix_values[row][col] = val
        self._update_tree_internal(row + 1, col + 1, diff)

    def _query_tree_internal(self, r_idx, c_idx):
        # r_idx, c_idx are 1-based indices for the tree
        total_sum = 0
        while r_idx > 0:
            current_c_idx = c_idx
            while current_c_idx > 0:
                total_sum += self.tree[r_idx][current_c_idx]
                current_c_idx -= current_c_idx & (-current_c_idx)
            r_idx -= r_idx & (-r_idx)
        return total_sum

    def query(self, row, col):
        # Query sum from (0,0) to (row,col) inclusive
        # row, col are 0-based indices
        if not (0 <= row < self.rows and 0 <= col < self.cols):
            return 0 
        return self._query_tree_internal(row + 1, col + 1)

    def range_query(self, r1, c1, r2, c2):
        # Query sum of rectangle (r1,c1) to (r2,c2) inclusive
        # r1, c1, r2, c2 are 0-based indices
        if not (0 <= r1 <= r2 < self.rows and 0 <= c1 <= c2 < self.cols):
            return 0

        # Using inclusion-exclusion principle
        sum_r2_c2 = self._query_tree_internal(r2 + 1, c2 + 1)
        sum_r1_minus_1_c2 = self._query_tree_internal(r1, c2 + 1)
        sum_r2_c1_minus_1 = self._query_tree_internal(r2 + 1, c1)
        sum_r1_minus_1_c1_minus_1 = self._query_tree_internal(r1, c1)

        return sum_r2_c2 - sum_r1_minus_1_c2 - sum_r2_c1_minus_1 + sum_r1_minus_1_c1_minus_1
